INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('18f1dfb8d63a8426', 'UT', '["federal","state","county"]', 'ballot_access', 'What is Utah''s dual-path primary system?', '["How does SB54 work in Utah?","Utah dual-path ballot access explained","Two ways to get on the ballot in Utah"]', 'Under Utah''s SB54 law, candidates in a Qualified Political Party (QPP) have a dual-path system to access the primary ballot. They can choose to: 1) Compete in the traditional caucus-convention system, or 2) Bypass the convention by gathering voter signatures. Candidates may pursue either path, or both simultaneously, to secure a spot on the primary ballot.', 'https://vote.utah.gov/candidate-information/', 'Utah Lieutenant Governor - Candidate Resources', '2026-04-21', 'static', 'official_source_direct', 'All partisan candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('e8bf50d300ecb25a', 'UT', '["federal","state","county"]', 'ballot_access', 'How does the caucus-convention path work in Utah?', '["Utah convention 60 percent rule","How do delegates select nominees in Utah?","Bypassing the primary via convention UT"]', 'In the caucus-convention path, delegates vote on candidates at the state party convention. If a candidate receives 60% or more of the delegate vote, they become the party''s nominee and bypass the primary ENTIRELY—provided no other candidate qualified via the signature path. If no candidate reaches 60%, the top two candidates (typically those receiving 40-60%) advance to a primary election.', 'https://vote.utah.gov/candidate-information/', 'Utah Lieutenant Governor - Candidate Resources', '2026-04-21', 'static', 'official_source_direct', 'All partisan candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('f0c4f784e76062e5', 'UT', '["federal","state","county"]', 'ballot_access', 'How does the signature gathering path work in Utah?', '["Bypassing the convention with signatures Utah","How many signatures to get on the primary ballot in UT?","SB54 signature track"]', 'The signature-gathering path allows a candidate to bypass the convention process and guarantee their name on the primary ballot. If a candidate gathers the statutory number of signatures (e.g., 7,000 for U.S. House, 2,000 for State Senate, 1,000 for State House), they force a primary election, even if a convention opponent receives more than 60% of the delegate vote.', 'https://vote.utah.gov/candidate-information/', 'Utah Lieutenant Governor - Candidate Resources', '2026-04-21', 'static', 'official_source_direct', 'All partisan candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('c459e42a1aa8a5e0', 'UT', '["federal","state","county"]', 'ballot_access', 'Is SB54''s dual-path primary system operative for 2026?', '["Did the Utah legislature repeal SB54?","Is the signature path still legal in Utah?","SB54 political status 2026"]', 'Yes. While SB54 is a highly volatile and intensely debated law—with strong opposition from certain state party delegates and some federal officials advocating for a return to a strict convention-only system—repeal efforts have not succeeded. The dual-path system remains fully operative for the 2026 cycle.', 'https://le.utah.gov/xcode/Title20A/Chapter9/20A-9-P4.html', 'Utah Code Title 20A, Chapter 9, Part 4', '2026-04-21', 'volatile', 'statute_citation', 'All partisan candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('504e8eac5e7a18be', 'UT', '["federal","state","county"]', 'ballot_access', 'How do minor party and independent candidates get on the general election ballot in Utah?', '["Independent candidate ballot access Utah","Running without a party in UT","Unaffiliated candidate petition threshold Utah"]', 'Unaffiliated (independent) candidates bypass the primary and petition directly onto the general election ballot. They must declare candidacy between early January and June 15 of the election year. They must submit verified signatures totaling 300 voters or 5% of the registered voters residing in the district, whichever is less.', 'https://vote.utah.gov/candidate-information/', 'Utah Lieutenant Governor - Candidate Resources', '2026-04-21', 'per_cycle', 'official_source_direct', 'Independent candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('4207ba7b0c4a0b73', 'UT', '["federal","state","county"]', 'ballot_access', 'What are the requirements for write-in candidates in Utah?', '["Do write-in votes count in UT?","Utah write-in candidate registration","Declaration of intent write-in Utah"]', 'To have write-in votes counted in Utah, a candidate must officially file a Declaration of Write-In Candidacy with the appropriate filing officer no later than 65 days before the regular general election. Votes cast for undeclared write-in candidates will not be tabulated.', 'https://le.utah.gov/xcode/Title20A/Chapter9/20A-9-S601.html', 'Utah Code § 20A-9-601', '2026-04-21', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('1c4733e0108acf71', 'UT', '["federal","state","county"]', 'ballot_access', 'Does Utah have a sore loser law?', '["Can I run as an independent if I lose the UT primary?","Utah sore loser statute","General election ballot access after convention defeat UT"]', 'Yes. Under Utah Code § 20A-9-202(6), a person who is defeated as a candidate in a primary election or a party convention may not file a declaration of candidacy as an independent (unaffiliated) candidate or as a write-in candidate for the same office in the same election year.', 'https://le.utah.gov/xcode/Title20A/Chapter9/20A-9-S202.html', 'Utah Code § 20A-9-202', '2026-04-21', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('8ec9bf6d323fbdee', 'UT', '["state"]', 'ballot_access', 'What is a Qualified Political Party (QPP) in Utah?', '["Registered vs Qualified political party Utah","QPP status Utah","Which parties use the dual-path primary in UT?"]', 'In Utah, a Qualified Political Party (QPP) is a recognized political party that explicitly permits delegates to vote in a convention AND allows candidates to bypass the convention via signature gathering (the SB54 dual-path system). Currently, the major parties (Republican and Democratic) operate as QPPs. Non-QPPs are classified as Registered Political Parties and only use the convention path.', 'https://vote.utah.gov/political-parties/', 'Utah Lieutenant Governor - Political Parties', '2026-04-21', 'static', 'official_source_direct', 'Political parties', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('8ffb7468146c0da9', 'UT', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Utah for 2026?', '["Utah primary date 2026","When is Election Day 2026 in Utah?","June primary Utah"]', 'The Utah primary election will be held on Tuesday, June 23, 2026. The general election will be held on Tuesday, November 3, 2026. Polls open at 7:00 a.m. and close at 8:00 p.m.', 'https://vote.utah.gov/', 'Utah Lieutenant Governor - Election Dates', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('646c891a0ade5805', 'UT', '["state"]', 'election_dates', 'Is Governor Spencer Cox running for re-election in 2026?', '["Utah Governor election 2026","Who is defending the UT Governor seat?","Is Spencer Cox on the 2026 ballot?"]', 'No. Utah elects its Governor in presidential years. Governor Spencer Cox was re-elected in 2024 and his four-year term runs until early 2029. There is no gubernatorial race in 2026.', 'https://ballotpedia.org/Governor_of_Utah', 'Ballotpedia - Governor of Utah', '2026-04-21', 'static', 'secondary_source', 'Statewide candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('c333c95b972d58cc', 'UT', '["federal"]', 'election_dates', 'Which U.S. Senate seats are up for election in Utah in 2026?', '["Is Mike Lee up for re-election in 2026?","When is John Curtis''s next election?","Utah US Senate cycle 2026"]', 'No U.S. Senate seats are on the 2026 ballot in Utah. Both seats were recently decided: Mike Lee (Class 3) was re-elected in 2022 and will not run again until 2028. John Curtis (Class 1) was elected in 2024 and will not run again until 2030.', 'https://vote.utah.gov/', 'Utah Lieutenant Governor', '2026-04-21', 'per_cycle', 'official_source_direct', 'Federal candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('6e07c9dddd7053d5', 'UT', '["federal"]', 'election_dates', 'How many U.S. House districts are in Utah for the 2026 election?', '["Utah congressional apportionment","Are all UT congressional seats up in 2026?","Court ordered redistricting Utah US House"]', 'Utah is apportioned 4 U.S. House districts, and all 4 are up for election in 2026. Significantly, the 2026 midterm races will be contested using a newly implemented court-ordered map resulting from an anti-gerrymandering lawsuit that successfully un-split Salt Lake County.', 'https://www.democracydocket.com/news-alerts/utah-supreme-court-upholds-fairer-map-for-midterm-elections/', 'Democracy Docket - Utah Redistricting Case', '2026-04-21', 'volatile', 'secondary_source', 'Federal candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('365ade2e8d18ba3b', 'UT', '["state"]', 'election_dates', 'Which Utah State Legislature seats are up for election in 2026?', '["Are all Utah House seats up in 2026?","Utah Senate election cycle 2026","Which legislative districts are on the ballot in UT?"]', 'All 75 seats in the Utah House of Representatives (2-year terms) are up for election in 2026. The Utah State Senate has 29 members who serve staggered 4-year terms; approximately half of the Senate seats (15 districts) will be on the 2026 ballot.', 'https://le.utah.gov/', 'Utah State Legislature', '2026-04-21', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('c6d48a9b52c88f37', 'UT', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Utah in 2026?', '["Is the Attorney General up in 2026?","UT statewide election list 2026","When is the next State Treasurer election in UT?"]', 'None. Utah elects all of its partisan statewide executive officers—Governor, Lt. Governor, Attorney General, State Auditor, and State Treasurer—on the presidential election cycle (e.g., 2024, 2028). There are no statewide partisan executive offices on the 2026 midterm ballot.', 'https://ballotpedia.org/State_executive_official_elections,_2026', 'Ballotpedia - State Executive Elections 2026', '2026-04-21', 'per_cycle', 'secondary_source', 'Statewide candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('c3d3cd39e5639778', 'UT', '["state"]', 'election_dates', 'What is the schedule for Utah''s part-time legislative sessions?', '["When does the UT legislature meet?","Utah 45 day legislative session","Is the Utah legislature full time?"]', 'The Utah Legislature is a part-time ''citizen'' legislature. It meets annually for a general session that begins in January and is constitutionally limited to exactly 45 calendar days. The session typically concludes in early March.', 'https://le.utah.gov/', 'Utah State Legislature', '2026-04-21', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('ff9ff48796c3293e', 'UT', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Utah?', '["Age and residency for Utah Governor","Utah Constitution Article VII Governor qualifications","Who is eligible to be Governor of Utah?"]', 'Under Article VII, Section 3 of the Utah Constitution, a candidate for Governor must be at least 30 years old, a citizen of the United States, and must have been a resident of Utah for at least five years preceding the election.', 'https://le.utah.gov/xcode/ArticleVII/Article_VII,_Section_3.html', 'Utah Constitution Article VII, Section 3', '2026-04-21', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('51830dba70ae3618', 'UT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Utah?', '["Utah Lt Gov requirements","Does the Lt Gov run on a joint ticket in UT?","Qualifications for Lieutenant Governor of Utah"]', 'The constitutional requirements for Lieutenant Governor in Utah are identical to those for the Governor: at least 30 years old, a U.S. citizen, and a resident of the state for five years. Furthermore, the Governor and Lieutenant Governor must run on a joint ticket in both the primary and general elections.', 'https://le.utah.gov/xcode/ArticleVII/Article_VII,_Section_3.html', 'Utah Constitution Article VII, Section 3', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('ef7ed1d362cb119e', 'UT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Utah State Legislature?', '["Qualifications for UT State Representative","Residency requirement Utah State Senate","Do I have to live in my district to run in UT?"]', 'Under Article VI, Section 5 of the Utah Constitution, a candidate for the State Senate or House of Representatives must be at least 25 years old, a U.S. citizen, a resident of Utah for three years, and a resident of the specific district they seek to represent for at least six months prior to the election.', 'https://le.utah.gov/xcode/ArticleVI/Article_VI,_Section_5.html', 'Utah Constitution Article VI, Section 5', '2026-04-21', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('975dc96bd61e5eb7', 'UT', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Utah?', '["US Senate residency requirements Utah","Age to run for Congress in Utah","Federal constitutional requirements for UT candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://vote.utah.gov/candidate-information/', 'Utah Lieutenant Governor - Candidate Resources', '2026-04-21', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('042384fc14930a59', 'UT', '["state"]', 'candidate_eligibility', 'Does the Utah Attorney General have to be a licensed attorney?', '["Qualifications to run for Attorney General in UT","Do I need to be a member of the bar to be UT AG?","Legal requirements for Utah Attorney General"]', 'Yes. Under Article VII, Section 3 of the Utah Constitution, the Attorney General must be at least 25 years of age, a resident of the state for five years, and must be ''admitted to practice before the Supreme Court of the State of Utah'' in good standing.', 'https://le.utah.gov/xcode/ArticleVII/Article_VII,_Section_3.html', 'Utah Constitution Article VII, Section 3', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('1b606a2fac1b1e28', 'UT', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for County Commissioner in Utah?', '["Utah county commissioner qualifications","Can I run for county board in UT?","County residency for UT commissioners"]', 'To run for County Commissioner or County Council in Utah, a candidate must be a registered voter and have been a resident of the county (and the specific district, if applicable) for at least one year immediately preceding the date of the election.', 'https://vote.utah.gov/candidate-information/', 'Utah Lieutenant Governor - Candidate Resources', '2026-04-21', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('182e32a83feb67c8', 'UT', '["state","county"]', 'candidate_eligibility', 'Does Utah have term limits for elected officials?', '["Term limits for Utah Governor","How many terms can a Utah state senator serve?","Are there term limits for the Utah House?"]', 'No. Utah does not have term limits for the Governor, statewide executive officers, state legislators, or county officials. Candidates may serve an unlimited number of terms as long as they are continually re-elected.', 'https://ballotpedia.org/Utah_State_Legislature', 'Ballotpedia - Utah Term Limits', '2026-04-21', 'static', 'secondary_source', 'All state and local candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('76285242d456e4a5', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Utah a universal mail ballot state?', '["Do all voters get a mail ballot in Utah?","Utah vote-by-mail system","Are there traditional polling places in UT?"]', 'Yes. Utah is a universal vote-by-mail state. All active registered voters are automatically mailed a ballot approximately three weeks before every election. However, voters maintain the option to vote in person at designated vote centers during early voting or on Election Day.', 'https://vote.utah.gov/how-to-vote/', 'Utah Lieutenant Governor - How to Vote', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('9c5214d780fa82b0', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Utah use traditional polling precincts or vote centers?', '["Where do I vote in person in Utah?","Utah vote centers vs precincts","Can I vote anywhere in my county in UT?"]', 'Utah predominantly uses ''vote centers'' rather than strictly assigning voters to individual, neighborhood-based polling precincts. Any registered voter in a county can cast their ballot at any authorized vote center within that same county on Election Day.', 'https://vote.utah.gov/how-to-vote/', 'Utah Lieutenant Governor - Vote Centers', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('9f7453e1d829436c', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return a mail ballot in Utah?', '["When is the last day to mail my ballot in UT?","Mail ballot postmark deadline Utah","Utah drop box deadline"]', 'In Utah, a completed mail ballot must either be dropped off at a designated drop box by 8:00 p.m. on Election Day OR, if sent through the USPS, it must be clearly postmarked no later than the day BEFORE Election Day to be counted.', 'https://vote.utah.gov/how-to-vote/', 'Utah Lieutenant Governor - Voting by Mail', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('78cc4d7b6fcc8a7f', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Utah allow same-day voter registration?', '["Late registration Utah","Can I register to vote on Election Day in UT?","Utah voter registration deadline"]', 'Yes. While the standard voter registration deadline (online or by mail) is 11 days before the election, Utah allows same-day voter registration at early voting locations and at vote centers on Election Day. Voters utilizing this option will cast a provisional ballot and must present a valid photo ID and proof of residency.', 'https://vote.utah.gov/voter-registration/', 'Utah Lieutenant Governor - Voter Registration', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('957e77b891accba3', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Utah?', '["Utah voter ID requirements","Do I need my driver''s license to vote in UT?","In-person voting ID laws Utah"]', 'Yes. Utah requires a valid form of identification to vote in person. Voters must present ONE primary form of ID (such as a Utah driver''s license, U.S. passport, or tribal ID) OR TWO forms of secondary ID that, when combined, prove their name and current residential address (such as a utility bill and a bank statement).', 'https://vote.utah.gov/voter-id-requirements/', 'Utah Lieutenant Governor - Voter ID Requirements', '2026-04-21', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('f39bc6bd0bb9b9fe', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'Which agency administers elections in Utah?', '["Does the Secretary of State run elections in Utah?","Who is the chief election officer in UT?","Utah election administration"]', 'Unlike most states where the Secretary of State serves as the chief election officer, in Utah, elections are administered by the Office of the Lieutenant Governor. The Lieutenant Governor oversees state elections, campaign finance, and county clerks who execute the elections locally.', 'https://vote.utah.gov/', 'Utah Lieutenant Governor', '2026-04-21', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('3a8025b6b368ad0f', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Utah?', '["How close can I campaign to a polling place in UT?","Buffer zone around voting centers Utah","UT electioneering rules 150 feet"]', 'Under Utah Code § 20A-3a-501, electioneering is strictly prohibited within 150 feet of any polling location (vote center) or official ballot drop box. This includes distributing campaign literature, wearing campaign apparel, or soliciting votes.', 'https://le.utah.gov/xcode/Title20A/Chapter3A/20A-3a-S501.html', 'Utah Code § 20A-3a-501', '2026-04-21', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('25d58fb06048dacb', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Utah?', '["Can felons vote in Utah state?","Felony voting rights restoration UT","Voting on parole in Utah"]', 'In Utah, an individual with a felony conviction only loses their right to vote while they are actively incarcerated in a prison serving their sentence. Voting rights are automatically restored immediately upon release from incarceration. Individuals on probation or parole are fully eligible to vote.', 'https://le.utah.gov/xcode/Title20A/Chapter2/20A-2-S101.5.html', 'Utah Code § 20A-2-101.5', '2026-04-21', 'static', 'statute_citation', 'Voters', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('45777f1a4799a76e', 'UT', '["state","county"]', 'finance_ethics', 'What are the campaign contribution limits in Utah for the 2026 cycle?', '["How much can an individual donate to a UT Governor candidate?","Current campaign contribution limits for state legislature in UT","Utah individual donation caps 2026 election"]', 'Utah has NO contribution limits for candidates running for state or local office. Individuals, PACs, and political parties may contribute completely unlimited amounts of money to state-level campaigns. It is one of the few states in the country with zero contribution caps.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor - Campaign Finance', '2026-04-21', 'static', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('0ef0e5b0711a253c', 'UT', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Utah?', '["Where do I file campaign finance reports in UT?","What is the Utah Disclosures portal?","Does the UT Lt Gov handle campaign finance?"]', 'Campaign finance and disclosure laws in Utah are administered by the Office of the Lieutenant Governor. All state and local candidates must register and file their contribution and expenditure reports through the mandatory online portal called disclosures.utah.gov.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor - Disclosures Portal', '2026-04-21', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('94296954e0264acf', 'UT', '["state","county","municipal"]', 'finance_ethics', 'When must a Utah candidate register their campaign committee?', '["Utah campaign committee registration timeline","When do I have to select a personal campaign committee in UT?","Utah statement of organization threshold"]', 'Under Utah Code § 20A-11-201, a state office candidate must select a personal campaign committee and register it with the Lieutenant Governor''s office prior to receiving any contributions or making any expenditures. A candidate is permitted to serve as their own campaign committee.', 'https://le.utah.gov/xcode/Title20A/Chapter11/20A-11-S201.html', 'Utah Code § 20A-11-201', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('195166e2e03a0b43', 'UT', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Utah candidates?', '["UT campaign finance filing dates","When are disclosure reports due in Utah?","Utah pre-primary and pre-general report deadlines"]', 'State candidates must file periodic financial disclosure reports. Key reporting deadlines include 7 days before the primary election, 30 days after the primary election, 7 days before the general election, 30 days after the general election, and a year-end summary report due January 10th of every year.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor - Reporting Dates', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('03c7dbee680fd3b9', 'UT', '["state","county","municipal"]', 'finance_ethics', 'What are Utah''s rapid disclosure requirements for large contributions?', '["Utah 7-day large contribution report","Late contribution reporting Utah","When do I file a rapid report in UT?"]', 'Under Utah Code § 20A-11-201, if a state office candidate receives a contribution within the 30-day window immediately preceding a convention, primary election, or general election, they must report that contribution electronically within seven (7) business days of receipt.', 'https://le.utah.gov/xcode/Title20A/Chapter11/20A-11-S201.html', 'Utah Code § 20A-11-201', '2026-04-21', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('1414ddd35fb6cadb', 'UT', '["state","county","municipal"]', 'finance_ethics', 'Are corporate and union contributions permitted in Utah campaigns?', '["Corporate contribution ban Utah state","Can a business donate to my campaign in UT?","Corporate campaign finance rules Utah"]', 'Yes. Utah permits direct corporate and labor union contributions to candidate campaigns. Because Utah has no contribution limits for state-level candidates, these corporate contributions may be made in completely unlimited amounts, provided they are properly disclosed.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor - Campaign Finance', '2026-04-21', 'static', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('ed7de6ec4c08b91f', 'UT', '["state"]', 'finance_ethics', 'Does Utah provide public financing for state campaigns?', '["Public matching funds for Utah Governor","State funded campaigns Utah status","Government campaign grants Utah"]', 'No. Utah does not have a system of public financing or matching funds for political campaigns. All candidates must fund their campaigns entirely through private contributions from individuals, PACs, corporations, and political parties.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor', '2026-04-21', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('f8d7b25f36a3fa64', 'UT', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Utah?', '["UT personal use prohibition campaign finance","Can I use campaign money for personal expenses in Utah?","Prohibited expenditures Utah Disclosures portal"]', 'Yes. Utah Code § 20A-11-104 explicitly prohibits candidates and officeholders from expending campaign funds for personal use. Funds must be utilized exclusively for political purposes, campaign-related costs, or ordinary and necessary expenses incurred in connection with the duties of holding public office.', 'https://le.utah.gov/xcode/Title20A/Chapter11/20A-11-S104.html', 'Utah Code § 20A-11-104', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('d4a56feb47b0ed50', 'UT', '["federal","state"]', 'redistricting', 'Who is responsible for drawing Utah''s legislative and congressional maps?', '["Does Utah use an independent redistricting commission?","Who has the authority to draw district lines in Utah?","Redistricting process Utah"]', 'Utah uses the Utah Independent Redistricting Commission (UIRC), originally created by citizen initiative (Proposition 4). While the legislature historically attempted to reduce the commission to an advisory role, recent landmark Utah Supreme Court rulings have reinstated the commission''s authority, mandating that the legislature cannot simply ignore the commission''s anti-gerrymandering maps.', 'https://le.utah.gov/xcode/Title20A/Chapter20/20A-20.html', 'Utah Code Title 20A, Chapter 20 / Supreme Court Rulings', '2026-04-21', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('65e1d2e9a57f635c', 'UT', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Utah?', '["Standards for drawing Utah district lines","Utah gerrymandering rules","UIRC map requirements UT"]', 'Under Proposition 4 guidelines, redistricting maps must achieve population equality, be contiguous and reasonably compact, preserve communities of interest, minimize the division of municipalities and counties, and strictly prohibit partisan gerrymandering that intentionally favors or disfavors any political party or candidate.', 'https://le.utah.gov/xcode/Title20A/Chapter20/20A-20-S302.html', 'Utah Code § 20A-20-302', '2026-04-21', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('8e14eeda4bc14ad4', 'UT', '["federal"]', 'redistricting', 'Are the current Utah congressional maps operative for the 2026 election cycle?', '["Court ordered redistricting Utah US House","Are there pending redistricting lawsuits in Utah?","Utah 2026 district boundaries"]', 'Yes, but they are newly implemented court-ordered maps. Following a prolonged legal battle (League of Women Voters of Utah v. Utah State Legislature), a state trial court in early 2026 struck down the legislature''s map as an illegal partisan gerrymander. The court imposed a remedial map operative for 2026, which notably creates a highly competitive congressional district centered around Salt Lake City.', 'https://statecourtreport.org/case-tracker/league-women-voters-utah-v-utah-state-legislature-lwv-1', 'League of Women Voters of Utah v. Utah State Legislature', '2026-04-21', 'volatile', 'secondary_source', 'Federal candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('0cc721a81f678a34', 'UT', '["federal","state"]', 'redistricting', 'Can the Utah legislature override the redistricting commission''s maps?', '["Legislature override of Utah redistricting","Can UT lawmakers change district boundaries?","Utah redistricting amendment rules"]', 'The legislature''s power to override the commission is now strictly limited. In 2025, the Utah Supreme Court ruled that the legislature''s prior repeal of the citizen-led Proposition 4 violated voters'' fundamental right to reform their government. Consequently, the legislature cannot override the commission''s anti-gerrymandering mandates without surviving strict judicial scrutiny.', 'https://statecourtreport.org/case-tracker/league-women-voters-utah-v-utah-state-legislature-lwv-1', 'Utah Supreme Court Ruling (2025)', '2026-04-21', 'volatile', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('0dc093b0a3ffe668', 'UT', '["state"]', 'recall_rules', 'Does Utah have a recall mechanism for state officials?', '["Can the Governor of Utah be recalled?","How to recall a state senator in UT","Statewide recall election rules Utah"]', 'No. The State of Utah does not have any legal mechanism for the recall of state-level elected officials, including the Governor or members of the state legislature.', 'https://ballotpedia.org/Laws_governing_recall_in_Utah', 'Laws governing recall in Utah', '2026-04-21', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('8496258fcad6338b', 'UT', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Utah?', '["Utah county commissioner recall rules","Signature requirement local recall Utah","Recalling a mayor in UT"]', 'Unlike many western states, Utah does not permit the recall of local, county, or municipal elected officials. Elections or formal impeachment/removal proceedings are the only methods for replacing officials.', 'https://ballotpedia.org/Laws_governing_recall_in_Utah', 'Laws governing recall in Utah', '2026-04-21', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('8976c16a368f33ad', 'UT', '["state"]', 'ballot_access', 'What are the signature thresholds for a citizen initiative in Utah?', '["How to get an initiative on the UT ballot","Utah citizen initiative signature requirements","Geographic distribution rule for UT initiatives"]', 'To qualify a citizen initiative for the ballot, proponents must gather valid signatures equal to 8% of the total number of votes cast in the state for all candidates for President at the last regular general election. Additionally, Utah requires strict geographic distribution: this 8% threshold must be met in at least 26 of the state''s 29 State Senate districts.', 'https://vote.utah.gov/initiative-and-referendum-information/', 'Utah Lieutenant Governor - Initiative Requirements', '2026-04-21', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('e64a24efe9af1bbf', 'UT', '["state"]', 'ballot_access', 'Can the Utah legislature amend or veto citizen initiatives?', '["Utah Amendment D initiative veto power","Does the legislature control ballot measures in UT?","Can lawmakers repeal voter approved laws in Utah?"]', 'The legislature''s power over initiatives has been heavily restricted by recent court rulings. A recent legislative effort (Amendment D) that sought to grant the legislature constitutional veto power to amend or repeal voter-approved initiatives was voided by the courts for deceptive ballot language. Consequently, the Utah Supreme Court has affirmed that voters have a protected, fundamental right to reform government via initiative without absolute legislative interference.', 'https://statecourtreport.org/case-tracker/league-women-voters-utah-v-utah-state-legislature-lwv-1', 'Utah Supreme Court Initiative Rulings', '2026-04-21', 'volatile', 'secondary_source', 'Ballot measure committees and Strategists', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('0e2f575b805e267d', 'UT', '["state"]', 'ballot_access', 'What is Utah''s Proposition 4 (2018) and why is it important for 2026?', '["Utah anti-gerrymandering initiative","Did voters create the redistricting commission in UT?","Prop 4 litigation status Utah"]', 'Proposition 4 was a 2018 citizen initiative that created Utah''s independent redistricting commission and banned partisan gerrymandering. After the legislature repealed it, a multi-year lawsuit resulted in the Utah Supreme Court reinstating the initiative''s core anti-gerrymandering protections, directly resulting in the newly operative, court-ordered congressional map for the 2026 elections.', 'https://statecourtreport.org/case-tracker/league-women-voters-utah-v-utah-state-legislature-lwv-1', 'League of Women Voters of Utah v. Utah State Legislature', '2026-04-21', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('704673f4ee7becd1', 'UT', '["state"]', 'ballot_access', 'How does the Utah legislature refer a constitutional amendment to the voters?', '["Legislative referral process Utah","Referendum by legislature UT","Can the UT legislature put a constitutional amendment on the ballot?"]', 'The Utah State Legislature can refer a proposed constitutional amendment to the voters by securing a two-thirds supermajority vote of all elected members in both the House of Representatives and the State Senate. The amendment does not require the Governor''s signature to appear on the general election ballot.', 'https://le.utah.gov/xcode/ArticleXX3/Article_XX3,_Section_1.html', 'Utah Constitution Article XXIII, Section 1', '2026-04-21', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('f6a5e1d79144ef9f', 'UT', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in Utah?', '["Utah ballot measure pass threshold","Does a measure need a supermajority in UT?","Majority vote requirements Utah ballot measures"]', 'Once a citizen initiative or a legislatively referred constitutional amendment qualifies for the general election ballot in Utah, it requires a simple majority (over 50%) of the votes cast on that specific measure to pass.', 'https://vote.utah.gov/initiative-and-referendum-information/', 'Utah Lieutenant Governor - Initiative Information', '2026-04-21', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('becad2c74221de07', 'UT', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in Utah?', '["Requirements to run for UT Secretary of State","Who can run for Secretary of State in UT?","Does Utah have a Secretary of State?"]', 'Utah DOES NOT have a Secretary of State. It is one of the few states where this office does not exist. All duties typically assigned to a Secretary of State—including administering elections, enforcing campaign finance disclosures, and overseeing business filings—are constitutionally assigned to the Lieutenant Governor.', 'https://vote.utah.gov/', 'Utah Lieutenant Governor''s Office', '2026-04-21', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-15T20-31-22_utah_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('9499d2b1bdb49bf0', 'UT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Auditor in Utah?', '["Eligibility for Utah State Auditor","Who can run for State Auditor in UT?","Qualifications for UT financial officers"]', 'Under Article VII, Section 3 of the Utah Constitution, a candidate for State Auditor must be at least 25 years old at the time of their election, a U.S. citizen, and must have resided within Utah for at least five years preceding the election. While there is no constitutional CPA requirement, the office must adhere to Government Auditing Standards.', 'https://le.utah.gov/xcode/ArticleVII/Article_VII,_Section_3.html', 'Utah Constitution Article VII, Section 3', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('8218e5980a5c0572', 'UT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Treasurer in Utah?', '["Eligibility for Utah State Treasurer","Who can run for State Treasurer in UT?","Utah Treasurer residency requirements"]', 'Under Article VII, Section 3 of the Utah Constitution, candidates for State Treasurer share the exact same qualifications as the State Auditor: they must be at least 25 years old at the time of election, a citizen of the United States, and a resident of Utah for at least five years preceding the election.', 'https://le.utah.gov/xcode/ArticleVII/Article_VII,_Section_3.html', 'Utah Constitution Article VII, Section 3', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('9799380bfad9c331', 'UT', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Utah?', '["Run for school board Utah requirements","Who can be a school trustee in UT?","School board residency rules Utah"]', 'To run for a local school district board of education in Utah, a candidate must be a registered voter and physically reside within the specific local school board district they seek to represent at the time of filing and throughout their term.', 'https://vote.utah.gov/candidate-information/', 'Utah Lieutenant Governor - Candidate Resources', '2026-04-21', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('5f671ce529bfaa45', 'UT', '["judicial"]', 'candidate_eligibility', 'How are Utah Supreme Court justices selected and what are the qualifications?', '["Utah Supreme Court Justice eligibility","Years of practice required for UT Supreme Court","Are Utah judges elected or appointed?"]', 'Utah Supreme Court justices are appointed by the Governor from a list provided by a judicial nominating commission. After serving at least three years, they stand in a nonpartisan retention election. To be eligible, a candidate must be at least 30 years old, a U.S. citizen, an active member of the Utah State Bar, and a resident of Utah for at least five years.', 'https://le.utah.gov/xcode/ArticleVIII/Article_VIII,_Section_7.html', 'Utah Constitution Article VIII, Section 7', '2026-04-21', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('15910ea33fe1169b', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee ballots in Utah?', '["How to fix a rejected signature in UT","Utah ballot cure process deadline","Missing signature on UT mail ballot"]', 'If a mail ballot envelope has a missing signature or a signature mismatch, the county clerk is required to notify the voter. The voter is provided an opportunity to ''cure'' the defect by submitting a cure affidavit. The deadline for the county clerk to receive the cure affidavit is generally before the conclusion of the county canvass (typically within 1-2 weeks after the election).', 'https://vote.utah.gov/how-to-vote/', 'Utah Lieutenant Governor - Voting by Mail', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('3f8e6fa11e23c968', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Utah?', '["When are military ballots due in Utah?","UOCAVA return deadline UT","Overseas voting rules Utah state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. Voted ballots must be received by the county election office no later than 8:00 p.m. on Election Day to be tabulated.', 'https://vote.utah.gov/military-and-overseas-voters/', 'Utah Lieutenant Governor - Military & Overseas', '2026-04-21', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('f746bdecfb77ab3d', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Utah?', '["What is a provisional ballot in UT?","Voting without ID Utah","When do election workers issue provisional ballots?"]', 'Provisional ballots are primarily issued in Utah when a voter utilizes Same-Day Registration at an early voting center or on Election Day, or if there is a discrepancy with their ID or registration status in the poll book. The voter must provide valid ID and proof of residence before the county canvass to have the provisional ballot counted.', 'https://vote.utah.gov/how-to-vote/', 'Utah Lieutenant Governor - How to Vote', '2026-04-21', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('fae2005f0f03da76', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Utah have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Utah Driver License Division?","UT motor voter automatic registration","Do I have to register to vote if I get a UT driver''s license?"]', 'Yes. Utah employs a ''front-end opt-out'' Automatic Voter Registration (AVR) system at the Driver License Division (DLD). When an eligible citizen interacts with the DLD for a license or ID, they are presented with an electronic prompt asking if they wish to register to vote or update their existing registration. If they consent, the data is automatically transferred to election officials.', 'https://vote.utah.gov/voter-registration-portal/', 'Utah Lieutenant Governor - Voter Registration', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('7a3a95b72762f111', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Utah offer Online Voter Registration?', '["Can I register to vote online in UT?","Utah electronic voter registration","UT Lt Gov online registration portal"]', 'Yes. Eligible Utah residents with a valid state driver''s license or state-issued ID card can register to vote or update their registration electronically via the Lieutenant Governor''s Vote.Utah.gov portal. The strict online registration deadline is 11 days before an election.', 'https://vote.utah.gov/voter-registration-portal/', 'Utah Lieutenant Governor - Voter Registration', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('1222ddab81d3b55e', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Utah maintain its voter registration lists?', '["UT voter list maintenance rules","How are inactive voters handled in Utah?","Utah voter roll cleaning process"]', 'County clerks in Utah conduct regular list maintenance by cross-referencing death records, court felony conviction reports, and USPS National Change of Address (NCOA) data. If a voter is marked ''inactive'' and subsequently fails to vote in two consecutive regular general elections, their registration is purged.', 'https://vote.utah.gov/', 'Utah Lieutenant Governor', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('bb3bedede5474a7e', 'UT', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Utah voter file?', '["Utah voter database access cost","How to get the voter list in UT","What data is included in the Utah voter file?"]', 'Campaigns and political committees can purchase the statewide voter registration list from the Lieutenant Governor''s Office for a flat fee of $1,050. The tab-delimited file includes voter names, addresses, and voting history. However, state law strictly restricts the release of voters'' full dates of birth.', 'https://vote.utah.gov/obtain-voter-registration-or-election-data/', 'Utah Lieutenant Governor - Voter Data', '2026-04-21', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('2b1f9d9aec6b4b71', 'UT', '["federal","state","county"]', 'runoff_rules', 'Does Utah use runoff elections for close races?', '["Are there runoffs in Utah primaries?","How are tied elections decided in Utah?","Tie-breaker rules Utah elections"]', 'No. Utah does not hold traditional runoff elections for state or federal offices; the candidate receiving a plurality of the vote wins. In the event of an exact tie vote after recounts, Utah Code § 20A-1-304 dictates that the winning candidate is determined by drawing lots (e.g., flipping a coin or drawing names) in a public meeting.', 'https://le.utah.gov/xcode/Title20A/Chapter1/20A-1-S304.html', 'Utah Code § 20A-1-304', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('52659e6754b0475b', 'UT', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Utah?', '["Does Utah use ranked choice voting?","RCV status in Utah 2026","Instant runoff voting UT municipal"]', 'Ranked Choice Voting (RCV) is not used for statewide or federal elections in Utah; plurality voting remains the standard. However, Utah operates a ''Municipal Alternate Voting Methods Pilot Project'' which allows certain cities (such as Salt Lake City) to voluntarily opt-in to using RCV exclusively for their local municipal elections.', 'https://le.utah.gov/xcode/Title20A/Chapter4/20A-4-P6.html', 'Utah Code Title 20A, Chapter 4, Part 6', '2026-04-21', 'static', 'statute_citation', 'Local candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('2d5ff99b35a6f174', 'UT', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Utah campaign materials?', '["Utah ''Paid for by'' rules","Campaign ad disclaimer requirements UT","Political taglines Utah Disclosures portal"]', 'Utah requires all campaign advertising and political communications to include a clear sponsor identification line. The disclaimer must state ''Paid for by'' followed by the name of the candidate, political committee, or individual funding the material.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor - Campaign Finance', '2026-04-21', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('4b71766b93bc1d81', 'UT', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Utah?', '["UT campaign coordination rules","When is a PAC expenditure not independent in Utah?","Prohibition on candidate-PAC coordination UT"]', 'An expenditure is ''coordinated'' (and thus treated as an in-kind contribution) if the spending is made with the cooperation, consultation, or at the request or suggestion of a candidate or their committee. Because Utah has no contribution limits, coordinated spending is perfectly legal but must be fully disclosed as an in-kind contribution by the campaign.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor - Campaign Finance', '2026-04-21', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('82d6671726647179', 'UT', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Utah?', '["UT Disclosures portal late fee","Penalty for missing a Utah campaign finance deadline","Can a candidate be disqualified for late reporting in Utah?"]', 'The Lieutenant Governor rigorously enforces reporting deadlines. Failing to file a required report on the Disclosures portal incurs an immediate $100 fine. Crucially, under Utah Code § 20A-11-1002, failing to file specific pre-election reports on time can result in the candidate being legally disqualified, and their name may be removed from the ballot.', 'https://le.utah.gov/xcode/Title20A/Chapter11/20A-11-S1002.html', 'Utah Code § 20A-11-1002', '2026-04-21', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('0ca84f4806e11a7f', 'UT', '["state","county","municipal"]', 'finance_ethics', 'When and how must a Utah campaign committee terminate?', '["Closing a Utah campaign committee","Disclosures portal committee termination requirements","Final campaign finance report Utah"]', 'A candidate committee may formally terminate its registration on the Disclosures portal only when it has achieved a zero cash balance, disposed of all surplus funds legally, and resolved all outstanding debts or loans. A final summary report marking the committee as closed must be filed.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor - Campaign Finance', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('2c4564b344e2a7b7', 'UT', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Utah?', '["UT independent expenditure reporting Disclosures portal","Disclosure for UT independent expenditure groups","Reporting thresholds for outside spending Utah"]', 'Any person, corporation, or political committee making independent expenditures must file detailed expenditure reports through the Disclosures.utah.gov portal. If expenditures are made within the 30-day window leading up to an election, they trigger rapid disclosure requirements to ensure transparency.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor - Disclosures Portal', '2026-04-21', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('105a1e42af8c73f1', 'UT', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Utah?', '["Utah in-kind contribution valuation rules","Reporting non-monetary donations Utah campaign","Fair market value for in-kind gifts UT"]', 'In-kind contributions (donated goods, services, or equipment) must be reported on campaign financial disclosures at their fair market value—the standard price the campaign would have paid on the open market. They are reported simultaneously as both a receipt and an expenditure.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor - Campaign Finance', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('921a0033e7f4d3af', 'UT', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Utah?', '["Utah candidate personal loan limits","Can I pay myself back for a campaign loan in UT?","Reporting candidate loans in Disclosures portal"]', 'Because Utah has no contribution limits for state and local campaigns, a candidate may loan or contribute completely unlimited amounts of their own personal funds to their campaign. Loans must be properly documented in the Disclosures portal and can be repaid from future contributions.', 'https://disclosures.utah.gov/', 'Utah Lieutenant Governor', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('28b8069cc061476a', 'UT', '["state","county","municipal"]', 'finance_ethics', 'What can Utah candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in UT?","UT surplus campaign funds rules","Donating remaining campaign funds Utah"]', 'Unexpended campaign funds cannot be converted to personal use. Candidates may retain the funds for a future campaign, return them pro-rata to contributors, transfer them to a political party or PAC, or donate them to an IRS-recognized charitable organization.', 'https://le.utah.gov/xcode/Title20A/Chapter11/20A-11-S104.html', 'Utah Code § 20A-11-104', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('ac292257b5685a70', 'UT', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for lobbyists in Utah?', '["Can Utah legislators raise money during session?","Lobbyist contribution ban UT legislature","Legislative session contribution rules Utah"]', 'Yes. Under Utah Code § 36-11-304, it is unlawful for a lobbyist or a principal to make a campaign contribution to a state legislator or the Governor during the time the Legislature is convened in its annual general session, veto override session, or any special session.', 'https://le.utah.gov/xcode/Title36/Chapter11/C36-11-P3_1800010118000101.pdf', 'Utah Code § 36-11-304', '2026-04-21', 'static', 'statute_citation', 'State candidates and Lobbyists', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('83d19509f50b8d93', 'UT', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Utah?', '["When are county sheriffs elected in UT?","Utah county official term lengths","Are county assessors on the 2026 ballot?"]', 'Elected county officials in Utah—including Sheriffs, Assessors, Clerks, Treasurers, and Recorders—serve four-year terms. They are generally elected on staggered schedules, meaning specific county executive and County Commission/Council seats will be heavily featured on the 2026 midterm ballot.', 'https://vote.utah.gov/', 'Utah Lieutenant Governor', '2026-04-21', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('ce726b6e467061f7', 'UT', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Utah elections?', '["When are Utah election results official?","UT certification deadline","State Board of Canvassers meeting Utah"]', 'County boards of canvassers generally meet to certify local results between 7 and 14 days after the election. The State Board of Canvassers meets to officially canvass and certify the returns for statewide and federal offices no later than the fourth Monday in November.', 'https://vote.utah.gov/', 'Utah Lieutenant Governor - Canvass', '2026-04-21', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('0dd02ee89c5d6ab6', 'UT', '["federal","state"]', 'election_dates', 'When and how are special elections called in Utah?', '["Utah special election timeline","Who calls a special election to fill a US House vacancy in UT?","Filling a midterm vacancy Utah"]', 'Special elections to fill federal vacancies (such as for a U.S. House seat) are called by a proclamation from the Governor. Under Utah Code § 20A-1-502, the Governor must issue the proclamation within seven days of the vacancy occurring and schedule the special primary and general elections to align with existing election dates if possible.', 'https://le.utah.gov/xcode/Title20A/Chapter1/20A-1-S502.html', 'Utah Code § 20A-1-502', '2026-04-21', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-15T20-31-22_utah_full_v1'),
  ('9ebe0aa86628598b', 'UT', '["federal","state","county","municipal"]', 'election_dates', 'What are the polling hours on Election Day in Utah?', '["When do polls open in UT?","UT polling place hours","What time do polls close in Utah?"]', 'On Election Day, in-person vote centers in Utah are open from 7:00 a.m. to 8:00 p.m. local time. Under Utah Code § 20A-1-302, any qualified elector who is physically in line at the polling place at 8:00 p.m. is legally permitted to cast their ballot.', 'https://le.utah.gov/xcode/Title20A/Chapter1/20A-1-S302.html', 'Utah Code § 20A-1-302', '2026-04-21', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-15T20-31-22_utah_full_v1')
